    marginBottom: '10px',
    border: '1px solid #e0e0e0'
  },
  rangoHeader: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: '8px'
  },
  rangoTitle: { fontSize: '13px', fontWeight: 'bold', color: '#34495e' },
  removeRangoButton: {
    backgroundColor: '#e74c3c',
    color: 'white',
    border: 'none',
    borderRadius: '4px',
    width: '24px',
    height: '24px',
    cursor: 'pointer',
    fontSize: '12px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center'
  },
  formGroup: { display: 'flex', flexDirection: 'column', gap: '5px', marginBottom: '15px' },
  row: { display: 'flex', gap: '10px', marginBottom: '10px', alignItems: 'flex-end' },
  half: { flex: 1, display: 'flex', flexDirection: 'column', gap: '5px' },
  label: { fontSize: '12px', fontWeight: 'bold', color: '#34495e' },
  input: { padding: '8px', border: '1px solid #ddd', borderRadius: '4px', fontSize: '13px' },
  select: { padding: '8px', border: '1px solid #ddd', borderRadius: '4px', fontSize: '13px', backgroundColor: 'white' },
  addRangoButton: {
    width: '100%',
    padding: '8px',
    backgroundColor: '#3498db',
